// Parse incoming Telegram message
const body = $input.first().json;
const message = body.message || body.edited_message;

if (!message || !message.text) {
  return [{ json: { skip: true } }];
}

const text = message.text.trim();
const chatId = message.chat.id;
const userId = message.from?.id;
const username = message.from?.username || message.from?.first_name || 'Unknown';

// Parse command and args
const parts = text.split(' ');
const rawCmd = parts[0].toLowerCase();
const cmd = rawCmd.startsWith('/') ? rawCmd.slice(1) : rawCmd;
const args = parts.slice(1).join(' ');

return [{ json: { chatId, userId, username, cmd, args, rawText: text } }];

// Build /status reply – queries Coolify API
const chatId = $('Parse Command').first().json.chatId;
const args = $('Parse Command').first().json.args || 'all';

// Static response for now (wire to Coolify API in Phase 2)
const projects = [
  { name: 'IronForge', status: '🟢 Running' },
  { name: 'WarRoom', status: '🟢 Running' },
  { name: 'Matlogistik', status: '🟢 Running' },
  { name: 'Enhörningsligan', status: '🟢 Running' },
  { name: 'Taktpinne', status: '🟡 Rehab' },
];

const lines = projects.map(p => `  ${p.status} *${p.name}*`).join('\n');
const text = `🛰️ *Brotherhood Status*\n\`\`\`\n${lines}\n\`\`\`\n_Updated: ${new Date().toISOString().slice(0,16)} UTC_`;

return [{ json: { chatId, text, parseMode: 'Markdown' } }];

// Build /health reply
const chatId = $('Parse Command').first().json.chatId;

const checks = [
  { name: 'n8n', status: '🟢 OK' },
  { name: 'Coolify', status: '🟢 OK' },
  { name: 'Traefik', status: '🟢 OK' },
  { name: 'Disk (/)', status: '🟡 97% used' },
];

const lines = checks.map(c => `  ${c.status} ${c.name}`).join('\n');
const text = `❤️ *Health Check*\n\`\`\`\n${lines}\n\`\`\`\n_Tip: disk cleanup needed soon!_`;

return [{ json: { chatId, text, parseMode: 'Markdown' } }];

// Build /help reply
const chatId = $('Parse Command').first().json.chatId;

const text = `🤖 *Panopticon Agent — Commands*

/status — Project deployment status
/health — Infrastructure health check
/help — This help message

_Brotherhood WarRoom v2.0_`;

return [{ json: { chatId, text, parseMode: 'Markdown' } }];

// Unknown command handler
const chatId = $('Parse Command').first().json.chatId;
const cmd = $('Parse Command').first().json.cmd;

const text = `❓ Unknown command: */${cmd}*\nTry /help for available commands.`;

return [{ json: { chatId, text, parseMode: 'Markdown' } }];
